"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const slots=[['Morning','09:00'],['Midday','12:30'],['Evening','18:00']];
export default function RhythmTimeComposer(){const [time,setTime]=useState('09:00');const [active,setActive]=useState(0);const reduced=useReducedMotion();const choose=(i:number)=>{setActive(i);setTime(slots[i][1]);};return <form className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><label htmlFor="rhythm-time" className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">choose a time</label><div className="mt-3 flex flex-wrap gap-2">{slots.map((slot,i)=><motion.button key={slot[0]} type="button" aria-pressed={active===i} onClick={()=>choose(i)} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className="min-h-11 rounded-xl border border-[#ececee] px-3 text-sm font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{slot[0]}</motion.button>)}</div><input id="rhythm-time" type="time" value={time} onChange={e=>setTime(e.target.value)} className="mt-4 min-h-12 w-full rounded-xl border border-[#ececee] px-3 font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]"/><div className="mt-4 h-1 rounded-full bg-[#f4f5f6]"><motion.i animate={{x:active*96}} transition={reduced?{duration:.12}:{type:"spring",stiffness:350,damping:29}} className="block h-1 w-8 rounded-full bg-[#7c3aed]"/></div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Scheduled for {time}.</p></form>}
